import { getVideoComments } from "../services/comment.service.js";
import { ApiError } from "../utils/ApiError.js";

export const fetchComments = async (req, res, next) => {
  try {
    const { videoId } = req.params;

    // Pass the token generated by youtubeToken.middleware.js directly to the service
    const data = await getVideoComments(videoId, req.ytToken);

    res.status(200).json({
      success: true,
      data,
    });
  } catch (error) {
    // Pass errors correctly to the global error middleware handler
    next(new ApiError(500, "Failed to fetch Video Comments", [], error.stack));
  }
};